import React from 'react';
import { X, Trash2, Plus, Minus, CreditCard, MessageCircle } from 'lucide-react';
import { useCart } from '../context/CartContext';
import { CONTACT_INFO } from '../constants';

interface CartModalProps {
  onClose: () => void;
}

const CartModal: React.FC<CartModalProps> = ({ onClose }) => {
  const { cart, removeFromCart, updateQuantity, total, itemCount, clearCart } = useCart();

  const handleWhatsAppCheckout = () => {
    const orderDetails = cart.map(item => `${item.name} (x${item.quantity}) - ₦${item.price * item.quantity}`).join('\n');
    const message = `Hello Abeni! I would like to place an order:\n\n${orderDetails}\n\nTotal: ₦${total}\n\nPlease confirm availability and delivery!`;
    const url = `https://wa.me/${CONTACT_INFO.whatsappNumber}?text=${encodeURIComponent(message)}`;
    window.open(url, '_blank');
  };

  const handlePaystackCheckout = () => {
    // Note: This is a simulation using the window variable injected by the script in index.html
    const handler = (window as any).PaystackPop.setup({
      key: 'pk_test_xxxxxxxxxxxxxxxxxxxxxxxx', // Replace with your public key
      email: 'customer@email.com',
      amount: total * 100, // Amount in kobo
      currency: 'NGN',
      callback: (response: any) => {
        alert('Payment successful. Transaction reference: ' + response.reference);
        clearCart();
        onClose();
      },
      onClose: () => {
        alert('Transaction was not completed, window closed.');
      },
    });
    handler.openIframe();
  };

  return (
    <div className="fixed inset-0 z-[60] flex items-center justify-end">
      <div className="absolute inset-0 bg-black/60 backdrop-blur-sm" onClick={onClose}></div>

      <div className="relative w-full max-w-lg bg-white h-full flex flex-col shadow-2xl animate-[slideLeft_0.3s_ease-out]">
        <div className="p-6 border-b flex justify-between items-center bg-gray-50">
          <h2 className="text-2xl font-bold text-gray-800">Your Cart ({itemCount})</h2>
          <button onClick={onClose} className="p-2 hover:bg-gray-200 rounded-full transition-colors">
            <X size={24} />
          </button>
        </div>

        <div className="flex-grow overflow-y-auto p-6 space-y-6">
          {cart.length === 0 ? (
            <div className="text-center py-12">
              <p className="text-gray-500 mb-6">Your cart is currently empty.</p>
              <button onClick={onClose} className="text-[#FF7518] font-bold hover:underline">
                Browse Products
              </button>
            </div>
          ) : (
            cart.map(item => (
              <div key={item.id} className="flex space-x-4 bg-white border border-gray-100 p-4 rounded-2xl">
                <img src={item.image} alt={item.name} className="w-20 h-20 object-cover rounded-xl" />
                <div className="flex-grow">
                  <div className="flex justify-between items-start">
                    <h4 className="font-bold text-gray-900">{item.name}</h4>
                    <button onClick={() => removeFromCart(item.id)} className="text-red-400 hover:text-red-600">
                      <Trash2 size={18} />
                    </button>
                  </div>
                  <p className="text-sm text-gray-500 mb-3">₦{item.price} per pack</p>
                  <div className="flex justify-between items-center">
                    <div className="flex items-center space-x-2 bg-gray-100 rounded-lg px-2 py-1">
                      <button onClick={() => updateQuantity(item.id, -1)} className="p-1 hover:text-[#FF7518]">
                        <Minus size={14} />
                      </button>
                      <span className="font-bold text-sm w-4 text-center">{item.quantity}</span>
                      <button onClick={() => updateQuantity(item.id, 1)} className="p-1 hover:text-[#FF7518]">
                        <Plus size={14} />
                      </button>
                    </div>
                    <p className="font-bold text-[#228B22]">₦{item.price * item.quantity}</p>
                  </div>
                </div>
              </div>
            ))
          )}
        </div>

        {cart.length > 0 && (
          <div className="p-6 border-t bg-gray-50 space-y-4">
            <div className="flex justify-between items-center mb-4">
              <span className="text-gray-600 text-lg">Total Amount</span>
              <span className="text-2xl font-bold text-[#228B22]">₦{total.toLocaleString()}</span>
            </div>

            <button 
              onClick={handleWhatsAppCheckout}
              className="w-full bg-[#25D366] hover:bg-[#128C7E] text-white font-bold py-4 rounded-xl flex items-center justify-center space-x-2 shadow-lg transition-transform transform active:scale-95"
            >
              <MessageCircle size={20} />
              <span>Checkout via WhatsApp</span>
            </button>

            <button 
              onClick={handlePaystackCheckout}
              className="w-full bg-[#FF7518] hover:bg-[#e66a16] text-white font-bold py-4 rounded-xl flex items-center justify-center space-x-2 shadow-lg transition-transform transform active:scale-95"
            >
              <CreditCard size={20} />
              <span>Pay with Paystack</span>
            </button>
          </div>
        )}
      </div>
    </div>
  );
};

