import React from 'react';
import { ShoppingCart, Plus, Minus, Star } from 'lucide-react';
import { useCart } from '../context/CartContext';
import { PRODUCTS } from '../constants';

const ProductList: React.FC = () => {
  const { addToCart } = useCart();
  const [quantities, setQuantities] = React.useState<Record<string, number>>(
    PRODUCTS.reduce((acc, p) => ({ ...acc, [p.id]: 1 }), {})
  );

  const updateLocalQty = (id: string, delta: number) => {
    setQuantities(prev => ({
      ...prev,
      [id]: Math.max(1, (prev[id] || 1) + delta)
    }));
  };

  return (
    <section id="products" className="py-24 bg-white">
      <div className="max-w-7xl mx-auto px-4">
        <div className="text-center mb-20">
          <span className="text-[#FF7518] font-semibold tracking-[0.2em] uppercase text-xs mb-4 block">Premium Selection</span>
          <h2 className="text-4xl md:text-5xl font-bold text-slate-800 mb-6">Our Ripe Plantain Jars</h2>
          <div className="w-16 h-1 bg-[#FF7518] mx-auto mb-8 rounded-full"></div>
          <p className="text-slate-500 max-w-xl mx-auto text-lg font-light leading-relaxed">
            Choose your perfect size. Whether it's a personal snack or a family treat, Abeni delivers pure crunch.
          </p>
        </div>

        <div className="grid md:grid-cols-2 gap-12 max-w-5xl mx-auto">
          {PRODUCTS.map(product => (
            <div key={product.id} className="group bg-white rounded-[3rem] shadow-[0_4px_30px_rgba(0,0,0,0.03)] hover:shadow-[0_20px_70px_rgba(0,0,0,0.08)] transition-all duration-700 overflow-hidden flex flex-col border border-slate-50">
              <div className="relative h-96 overflow-hidden bg-slate-50">
                <img 
                  src={product.image} 
                  alt={product.name} 
                  className="w-full h-full object-contain p-4 group-hover:scale-110 transition-transform duration-[2000ms]"
                />
                <div className="absolute top-8 left-8 bg-white/95 backdrop-blur px-5 py-2.5 rounded-2xl text-slate-800 font-bold shadow-xl border border-slate-100">
                  ₦{product.price.toLocaleString()}
                </div>
                {product.id === 'pc-1000' && (
                  <div className="absolute top-8 right-8 bg-[#2E7D32] text-white px-4 py-2 rounded-2xl text-xs font-bold shadow-lg">
                    Best Value
                  </div>
                )}
              </div>

              <div className="p-10 flex-grow flex flex-col">
                <h3 className="text-2xl font-bold text-slate-800 mb-4">{product.name}</h3>
                <p className="text-slate-500 mb-10 flex-grow leading-relaxed font-light">{product.description}</p>

                <div className="flex items-center justify-between mt-auto gap-6">
                  <div className="flex items-center bg-slate-50 border border-slate-100 rounded-2xl px-5 py-3">
                    <button 
                      onClick={() => updateLocalQty(product.id, -1)}
                      className="text-slate-400 hover:text-[#FF7518] transition-colors p-1"
                    >
                      <Minus size={20} />
                    </button>
                    <span className="mx-6 font-bold w-6 text-center text-slate-700 text-lg">{quantities[product.id]}</span>
                    <button 
                      onClick={() => updateLocalQty(product.id, 1)}
                      className="text-slate-400 hover:text-[#FF7518] transition-colors p-1"
                    >
                      <Plus size={20} />
                    </button>
                  </div>

                  <button 
                    onClick={() => {
                      addToCart(product, quantities[product.id]);
                      setQuantities(prev => ({ ...prev, [product.id]: 1 }));
                      alert(`${product.name} added to cart!`);
                    }}
                    className="flex-grow bg-[#FF7518] hover:bg-[#e66a16] text-white font-bold py-4 px-8 rounded-2xl flex items-center justify-center space-x-3 transition-all shadow-xl hover:shadow-orange-100 active:scale-95"
                  >
                    <ShoppingCart size={22} />
                    <span>Add to Cart</span>
                  </button>
                </div>
              </div>
            </div>
          ))}
        </div>
      </div>
    </section>
  );
};

export default ProductList;
